次のコードを実行した後の count はいくつか。break は内側ループのみを終了させることに注意せよ。

let count = 0;
for (let i = 0; i < 3; i++) {
  for (let j = 0; j < 3; j++) {
    if (j === 1) {
      break;
    }
    count++;
  }
}

